import sys
from collections import deque, defaultdict
from typing import List

class Solution:
    def topologicalSort(self, graph: List[List[int]]) -> List[int]:
        n = len(graph)
        in_degree = [0] * n
        for u in range(n):
            for v in graph[u]:
                in_degree[v] += 1

        queue = deque([i for i in range(n) if in_degree[i] == 0])
        res = []

        while queue:
            u = queue.popleft()
            res.append(u)
            for v in graph[u]:
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    queue.append(v)

        return res if len(res) == n else [-1]

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        v, e = map(int, (next(it), next(it)))
        graph = [[] for _ in range(v)]
        for _ in range(e):
            u, w = map(int, (next(it), next(it)))
            graph[u].append(w)
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.topologicalSort(graph)
    if ans == [-1]:
        print('Cycle')
    else:
        print(' '.join(map(str, ans)))

