#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> topologicalSort(vector<vector<int>>& graph) {
        int n = graph.size();
        vector<int> in_degree(n, 0);
        for (int u = 0; u < n; u++) {
            for (int v : graph[u]) {
                in_degree[v]++;
            }
        }

        queue<int> q;
        for (int i = 0; i < n; i++) {
            if (in_degree[i] == 0) {
                q.push(i);
            }
        }
        vector<int> res;

        while (!q.empty()) {
            int u = q.front();
            q.pop();
            res.push_back(u);
            for (int v : graph[u]) {
                in_degree[v]--;
                if (in_degree[v] == 0) {
                    q.push(v);
                }
            }
        }

        return res.size() == n ? res : vector<int>(1, -1);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int v, e;
    if (!(cin >> v >> e)) return 0;
    vector<vector<int>> graph(v);
    for (int i = 0; i < e; i++) {
        int u, w;
        if (!(cin >> u >> w)) return 0;
        graph[u].push_back(w);
    }
    Solution sol;
    vector<int> ans = sol.topologicalSort(graph);
    if (ans.size() == 1 && ans[0] == -1) {
        cout << "Cycle" << '\n';
    } else {
        for (int i = 0; i < ans.size(); i++) {
            cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
        }
        cout << '\n';
    }
    return 0;
}
